class Solution(object):
    def resultArray(self, nums, k):
        n = len(nums)
        result = [0] * k
        # dp[r] = number of subarrays ending at current index with product % k == r
        dp = [0] * k
        for v in nums:
            new_dp = [0] * k
            vk = v % k
            # Extend existing subarrays
            for r in range(k):
                if dp[r] > 0:
                    new_dp[(r * vk) % k] += dp[r]
            # Start new subarray at current index
            new_dp[vk] += 1
            dp = new_dp
            for r in range(k):
                result[r] += dp[r]
        return result
